import React, { useMemo } from 'react';
import {
    LineChart,
    Line,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    Legend,
    ResponsiveContainer,
    Area,
    ComposedChart
} from 'recharts';
import type { Activity } from '../types';

interface SCurveViewProps {
    activities: Activity[];
}

export const SCurveView: React.FC<SCurveViewProps> = ({ activities }) => {

    const chartData = useMemo(() => {
        if (activities.length === 0) return [];

        // 1. Identify Range
        let minTime = Infinity;
        let maxTime = -Infinity;

        const allActivities = activities.filter(a => a.horaInicio && a.horaFim);

        allActivities.forEach(act => {
            const startP = new Date(act.horaInicio).getTime();
            const endP = new Date(act.horaFim).getTime();
            if (startP < minTime) minTime = startP;
            if (endP > maxTime) maxTime = endP;

            if (act.horaInicioReal && act.horaFimReal) {
                const startR = new Date(act.horaInicioReal).getTime();
                const endR = new Date(act.horaFimReal).getTime();
                if (startR < minTime) minTime = startR;
                if (endR > maxTime) maxTime = endR;
            }
        });

        if (minTime === Infinity) return [];

        // Round to start/end of days
        const startDate = new Date(minTime); startDate.setHours(0, 0, 0, 0);
        const endDate = new Date(maxTime); endDate.setHours(23, 59, 59, 999);

        // 2. Create timeline array
        const dayMs = 24 * 60 * 60 * 1000;
        const timeline: { date: string; timestamp: number; planned: number; real: number; cumulativePlanned: number; cumulativeReal: number }[] = [];

        for (let t = startDate.getTime(); t <= endDate.getTime(); t += dayMs) {
            timeline.push({
                date: new Date(t).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
                timestamp: t,
                planned: 0,
                real: 0,
                cumulativePlanned: 0,
                cumulativeReal: 0
            });
        }

        // 3. Distribute Hours
        allActivities.forEach(act => {
            const getDurationInHours = (s: string, e: string) => (new Date(e).getTime() - new Date(s).getTime()) / 3600000;

            // -- Planned --
            const startP = new Date(act.horaInicio).getTime();
            const endP = new Date(act.horaFim).getTime();
            const totalPlannedHours = getDurationInHours(act.horaInicio, act.horaFim);

            // Simple distribution: Assuming linear distribution across days overlap
            // Or simpler: Assign hours to the day it falls in. If spans multiple days, split proportionally.

            // Let's use proportional split
            const spanP = endP - startP;
            if (spanP > 0) {
                timeline.forEach(day => {
                    const dayStart = day.timestamp;
                    const dayEnd = day.timestamp + dayMs - 1;

                    // Check overlap
                    const overlapStart = Math.max(startP, dayStart);
                    const overlapEnd = Math.min(endP, dayEnd);

                    if (overlapEnd > overlapStart) {
                        const overlapRatio = (overlapEnd - overlapStart) / spanP;
                        day.planned += totalPlannedHours * overlapRatio;
                    }
                });
            }

            // -- Real --
            if (act.horaInicioReal && act.horaFimReal) {
                const startR = new Date(act.horaInicioReal).getTime();
                const endR = new Date(act.horaFimReal).getTime();
                const totalRealHours = getDurationInHours(act.horaInicioReal, act.horaFimReal);
                const spanR = endR - startR;

                if (spanR > 0) {
                     timeline.forEach(day => {
                        const dayStart = day.timestamp;
                        const dayEnd = day.timestamp + dayMs - 1;
                        const overlapStart = Math.max(startR, dayStart);
                        const overlapEnd = Math.min(endR, dayEnd);

                        if (overlapEnd > overlapStart) {
                            const overlapRatio = (overlapEnd - overlapStart) / spanR;
                            day.real += totalRealHours * overlapRatio;
                        }
                    });
                }
            }
        });

        // 4. Calculate Cumulative
        let accPlanned = 0;
        let accReal = 0;

        timeline.forEach(day => {
            accPlanned += day.planned;
            accReal += day.real;
            day.cumulativePlanned = Number(accPlanned.toFixed(2));
            day.cumulativeReal = Number(accReal.toFixed(2));
        });

        return timeline;

    }, [activities]);

    if (activities.length === 0) {
        return (
            <div className="flex items-center justify-center h-96 bg-white/70 dark:bg-gray-800/70 backdrop-blur-md rounded-lg shadow-lg">
                <p className="text-lg text-gray-500 dark:text-gray-400">Nenhuma atividade disponível para gerar a Curva S.</p>
            </div>
        );
    }

    const totalPlanned = chartData.length > 0 ? chartData[chartData.length - 1].cumulativePlanned : 0;
    const totalReal = chartData.length > 0 ? chartData[chartData.length - 1].cumulativeReal : 0;
    const deviation = totalReal - totalPlanned;

    return (
        <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="bg-white/70 dark:bg-gray-900/80 backdrop-blur-md p-4 rounded-lg shadow border border-blue-200 dark:border-blue-900">
                    <p className="text-xs font-bold text-gray-500 dark:text-gray-400 uppercase">Total Planejado Acumulado</p>
                    <p className="text-2xl font-bold text-blue-600 dark:text-blue-400">{totalPlanned.toFixed(1)} h</p>
                </div>
                <div className="bg-white/70 dark:bg-gray-900/80 backdrop-blur-md p-4 rounded-lg shadow border border-green-200 dark:border-green-900">
                    <p className="text-xs font-bold text-gray-500 dark:text-gray-400 uppercase">Total Real Acumulado</p>
                    <p className="text-2xl font-bold text-green-600 dark:text-green-400">{totalReal.toFixed(1)} h</p>
                </div>
                 <div className={`bg-white/70 dark:bg-gray-900/80 backdrop-blur-md p-4 rounded-lg shadow border ${deviation > 0 ? 'border-red-200 dark:border-red-900' : 'border-gray-200 dark:border-gray-700'}`}>
                    <p className="text-xs font-bold text-gray-500 dark:text-gray-400 uppercase">Desvio (Real - Planejado)</p>
                    <p className={`text-2xl font-bold ${deviation > 0 ? 'text-red-500' : 'text-green-500'}`}>
                        {deviation > 0 ? '+' : ''}{deviation.toFixed(1)} h
                    </p>
                </div>
            </div>

            <div className="bg-white/70 dark:bg-gray-900/80 backdrop-blur-md p-6 rounded-lg shadow-lg border border-gray-200/50 dark:border-gray-700/50 h-[500px]">
                <h3 className="text-lg font-semibold text-gray-800 dark:text-white mb-4">Curva S: Programado vs Real</h3>
                <ResponsiveContainer width="100%" height="100%">
                    <ComposedChart
                        data={chartData}
                        margin={{ top: 20, right: 30, left: 0, bottom: 0 }}
                    >
                        <CartesianGrid strokeDasharray="3 3" strokeOpacity={0.1} />
                        <XAxis 
                            dataKey="date" 
                            tick={{ fill: '#6b7280', fontSize: 12 }} 
                            axisLine={false}
                            tickLine={false}
                        />
                        <YAxis 
                            tick={{ fill: '#6b7280', fontSize: 12 }} 
                            axisLine={false}
                            tickLine={false}
                            label={{ value: 'Horas Acumuladas', angle: -90, position: 'insideLeft', style: { fill: '#9ca3af', fontSize: 12 } }}
                        />
                        <Tooltip 
                            contentStyle={{ backgroundColor: 'rgba(255, 255, 255, 0.9)', borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}
                            labelStyle={{ color: '#374151', fontWeight: 'bold' }}
                        />
                        <Legend verticalAlign="top" height={36} />

                        {/* Planned Line (S-Curve) */}
                        <Line 
                            type="monotone" 
                            dataKey="cumulativePlanned" 
                            name="Planejado Acumulado" 
                            stroke="#2563eb" 
                            strokeWidth={3} 
                            dot={false}
                            activeDot={{ r: 6 }}
                        />

                        {/* Real Line (S-Curve) */}
                        <Line 
                            type="monotone" 
                            dataKey="cumulativeReal" 
                            name="Real Acumulado" 
                            stroke="#16a34a" 
                            strokeWidth={3} 
                            dot={false}
                            activeDot={{ r: 6 }}
                        />

                        {/* Optional: Area under curve for visual weight */}
                        <Area type="monotone" dataKey="cumulativePlanned" fill="#2563eb" fillOpacity={0.05} stroke="none" legendType='none' />
                    </ComposedChart>
                </ResponsiveContainer>
            </div>
        </div>
    );
};

