                        onClick={handleSaveSettings} 
                        className="px-4 py-2 bg-green-600 hover:bg-green-700 text-white rounded shadow font-medium transition-colors flex items-center"
                    >
                        Salvar Alterações
                    </button>
                </div>
            </Modal>

            <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={editingActivity ? "Editar" : "Criar"}>
                <ActivityForm 
                    activity={editingActivity} 
                    onSubmit={editingActivity ? handleUpdateActivity : handleAddActivity} 
                    onClose={() => setIsModalOpen(false)} 
                    customStatusLabels={statusLabels}
                    onUpload={(file) => uploadFileToSupabase(file, `activities/${editingActivity?.tag || 'new'}`)}
                />
            </Modal>

            {viewingImage && <ImageViewerModal src={viewingImage} onClose={() => setViewingImage(null)} />}
        </div>
    );
};

export default App;

import React, { useMemo } from 'react';
import {
    LineChart,
    Line,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    Legend,
    ResponsiveContainer,
    Area,
    ComposedChart
} from 'recharts';
import type { Activity } from '../types';

interface SCurveViewProps {
    activities: Activity[];
}

export const SCurveView: React.FC<SCurveViewProps> = ({ activities }) => {

    const chartData = useMemo(() => {
        if (activities.length === 0) return { data: [], totalScope: 0 };

        const allActivities = activities.filter(a => a.horaInicio && a.horaFim);

        // 1. Calculate Total Planned Scope (100% base)
        let totalScopeHours = 0;
        allActivities.forEach(act => {
            const duration = (new Date(act.horaFim).getTime() - new Date(act.horaInicio).getTime()) / 3600000;
            totalScopeHours += duration;
        });

        if (totalScopeHours === 0) return { data: [], totalScope: 0 };

        // 2. Identify Time Range
        let minTime = Infinity;
        let maxTime = -Infinity;

        allActivities.forEach(act => {
            const startP = new Date(act.horaInicio).getTime();
            const endP = new Date(act.horaFim).getTime();
            if (startP < minTime) minTime = startP;
            if (endP > maxTime) maxTime = endP;

            if (act.horaInicioReal && act.horaFimReal) {
                const startR = new Date(act.horaInicioReal).getTime();
                const endR = new Date(act.horaFimReal).getTime();
                if (startR < minTime) minTime = startR;
                if (endR > maxTime) maxTime = endR;
            }
        });

        if (minTime === Infinity) return { data: [], totalScope: 0 };

        // Round to start/end of days
        const startDate = new Date(minTime); startDate.setHours(0, 0, 0, 0);
        const endDate = new Date(maxTime); endDate.setHours(23, 59, 59, 999);

        // 3. Create timeline array
        const dayMs = 24 * 60 * 60 * 1000;
        const timeline: { date: string; timestamp: number; planned: number; real: number; cumulativePlannedPct: number; cumulativeRealPct: number }[] = [];

        for (let t = startDate.getTime(); t <= endDate.getTime(); t += dayMs) {
            timeline.push({
                date: new Date(t).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
                timestamp: t,
                planned: 0,
                real: 0,
                cumulativePlannedPct: 0,
                cumulativeRealPct: 0
            });
        }

        // 4. Distribute Hours
        allActivities.forEach(act => {
            const getDurationInHours = (s: string, e: string) => (new Date(e).getTime() - new Date(s).getTime()) / 3600000;

            // -- Planned --
            const startP = new Date(act.horaInicio).getTime();
            const endP = new Date(act.horaFim).getTime();
            const totalPlannedHours = getDurationInHours(act.horaInicio, act.horaFim);

            const spanP = endP - startP;
            if (spanP > 0) {
                timeline.forEach(day => {
                    const dayStart = day.timestamp;
                    const dayEnd = day.timestamp + dayMs - 1;

                    const overlapStart = Math.max(startP, dayStart);
                    const overlapEnd = Math.min(endP, dayEnd);

                    if (overlapEnd > overlapStart) {
                        const overlapRatio = (overlapEnd - overlapStart) / spanP;
                        day.planned += totalPlannedHours * overlapRatio;
                    }
                });
            }

            // -- Real --
            if (act.horaInicioReal && act.horaFimReal) {
                const startR = new Date(act.horaInicioReal).getTime();
                const endR = new Date(act.horaFimReal).getTime();
                const totalRealHours = getDurationInHours(act.horaInicioReal, act.horaFimReal);
                const spanR = endR - startR;

                if (spanR > 0) {
                     timeline.forEach(day => {
                        const dayStart = day.timestamp;
                        const dayEnd = day.timestamp + dayMs - 1;
                        const overlapStart = Math.max(startR, dayStart);
                        const overlapEnd = Math.min(endR, dayEnd);

                        if (overlapEnd > overlapStart) {
                            const overlapRatio = (overlapEnd - overlapStart) / spanR;
                            day.real += totalRealHours * overlapRatio;
                        }
                    });
                }
            }
        });

        // 5. Calculate Cumulative Percentages
        let accPlanned = 0;
        let accReal = 0;

        timeline.forEach(day => {
            accPlanned += day.planned;
            accReal += day.real;

            // Calculate % against Total PLANNED Scope
            day.cumulativePlannedPct = Number(((accPlanned / totalScopeHours) * 100).toFixed(2));
            day.cumulativeRealPct = Number(((accReal / totalScopeHours) * 100).toFixed(2));
        });

        return { data: timeline, totalScope: totalScopeHours };

    }, [activities]);

    const data = chartData.data;

    if (activities.length === 0 || data.length === 0) {
        return (
            <div className="flex items-center justify-center h-96 bg-white/70 dark:bg-gray-800/70 backdrop-blur-md rounded-lg shadow-lg">
                <p className="text-lg text-gray-500 dark:text-gray-400">Nenhuma atividade disponível para gerar a Curva S.</p>
            </div>
        );
    }

    const currentPlannedPct = data.length > 0 ? data[data.length - 1].cumulativePlannedPct : 0;
    const currentRealPct = data.length > 0 ? data[data.length - 1].cumulativeRealPct : 0;
    const deviationPct = currentRealPct - currentPlannedPct;

    return (
        <div className="space-y-6">
            {/* KPI Cards */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="bg-white/70 dark:bg-gray-900/80 backdrop-blur-md p-4 rounded-lg shadow border border-blue-200 dark:border-blue-900">
                    <p className="text-xs font-bold text-gray-500 dark:text-gray-400 uppercase">Planejado Total</p>
                    <p className="text-2xl font-bold text-blue-600 dark:text-blue-400">{currentPlannedPct.toFixed(1)}%</p>
                    <p className="text-xs text-gray-400 mt-1">Base: {chartData.totalScope.toFixed(1)} horas</p>
                </div>
                <div className="bg-white/70 dark:bg-gray-900/80 backdrop-blur-md p-4 rounded-lg shadow border border-green-200 dark:border-green-900">
                    <p className="text-xs font-bold text-gray-500 dark:text-gray-400 uppercase">Realizado Total</p>
                    <p className="text-2xl font-bold text-green-600 dark:text-green-400">{currentRealPct.toFixed(1)}%</p>
                    <p className="text-xs text-gray-400 mt-1">Sobre o escopo planejado</p>
                </div>
                 <div className={`bg-white/70 dark:bg-gray-900/80 backdrop-blur-md p-4 rounded-lg shadow border ${deviationPct > 0 ? 'border-red-200 dark:border-red-900' : 'border-gray-200 dark:border-gray-700'}`}>
                    <p className="text-xs font-bold text-gray-500 dark:text-gray-400 uppercase">Desvio (%)</p>
                    <p className={`text-2xl font-bold ${deviationPct > 0 ? 'text-red-500' : 'text-gray-600 dark:text-gray-300'}`}>
                        {deviationPct > 0 ? '+' : ''}{deviationPct.toFixed(1)}%
                    </p>
                    <p className="text-xs text-gray-400 mt-1">{deviationPct > 0 ? 'Horas excedentes' : 'Dentro do planejado'}</p>
                </div>
            </div>

            {/* Chart */}
            <div className="bg-white/70 dark:bg-gray-900/80 backdrop-blur-md p-6 rounded-lg shadow-lg border border-gray-200/50 dark:border-gray-700/50 h-[500px]">
                <h3 className="text-lg font-semibold text-gray-800 dark:text-white mb-4">Curva S: % Planejado vs % Realizado</h3>
                <ResponsiveContainer width="100%" height="100%">
                    <ComposedChart
                        data={data}
                        margin={{ top: 20, right: 30, left: 0, bottom: 0 }}
                    >
                        <CartesianGrid strokeDasharray="3 3" strokeOpacity={0.1} />
                        <XAxis 
                            dataKey="date" 
                            tick={{ fill: '#6b7280', fontSize: 12 }} 
                            axisLine={false}
                            tickLine={false}
                        />
                        <YAxis 
                            tick={{ fill: '#6b7280', fontSize: 12 }} 
                            axisLine={false}
                            tickLine={false}
                            unit="%"
                            label={{ value: '% Concluído', angle: -90, position: 'insideLeft', style: { fill: '#9ca3af', fontSize: 12 } }}
                        />
                        <Tooltip 
                            formatter={(value: number) => [`${value}%`, '']}
                            contentStyle={{ backgroundColor: 'rgba(255, 255, 255, 0.95)', borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}
                            labelStyle={{ color: '#374151', fontWeight: 'bold' }}
                        />
                        <Legend verticalAlign="top" height={36} />

                        {/* Planned Line (S-Curve) */}
                        <Line 
                            type="monotone" 
                            dataKey="cumulativePlannedPct" 
                            name="% Planejado" 
                            stroke="#2563eb" 
                            strokeWidth={3} 
                            dot={false}
                            activeDot={{ r: 6 }}
                        />

                        {/* Real Line (S-Curve) */}
                        <Line 
                            type="monotone" 
                            dataKey="cumulativeRealPct" 
                            name="% Realizado" 
                            stroke="#16a34a" 
                            strokeWidth={3} 
                            dot={false}
                            activeDot={{ r: 6 }}
                        />

                        {/* Optional: Area under curve for visual weight */}
                        <Area type="monotone" dataKey="cumulativePlannedPct" fill="#2563eb" fillOpacity={0.05} stroke="none" legendType='none' />
                    </ComposedChart>
                </ResponsiveContainer>
            </div>
        </div>
    );
};

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { type Activity, ActivityStatus } from '../types';
import { PencilIcon } from './icons/PencilIcon';
import { PaperClipIcon } from './icons/PaperClipIcon';
import { CameraIcon } from './icons/CameraIcon';
import { ArrowsUpDownIcon } from './icons/ArrowsUpDownIcon';
import { TrashIcon } from './icons/TrashIcon';
import { getStatusClasses, getCriticidadeClasses, getStatusLabel } from '../utils/styleUtils';

interface ActivityListViewProps {
    activities: Activity[];
    onEdit: (activity: Activity) => void;
    onUpdateStatus: (activityId: string, status: ActivityStatus) => void;
    onDelete?: (activityId: string) => void;
    customStatusLabels?: Record<string, string>;
}

type SortDirection = 'asc' | 'desc';

interface SortConfig {
    key: keyof Activity | 'statusLabel' | null;
    direction: SortDirection;
}

export const ActivityListView: React.FC<ActivityListViewProps> = ({ activities, onEdit, onUpdateStatus, onDelete, customStatusLabels = {} }) => {
    // Sorting State
    const [sortConfig, setSortConfig] = useState<SortConfig>({ key: null, direction: 'asc' });

    // Resizing State
    const [columnWidths, setColumnWidths] = useState<Record<string, number>>({
        tag: 90,
        descricao: 280,
        responsavel: 130,
        supervisor: 130,
        turno: 70,
        data: 90, // Nova coluna
        horario: 110,
        duracao: 70,
        criticidade: 90,
        status: 130,
        anexos: 60,
        acoes: 70
    });

    const resizingRef = useRef<{ key: string; startX: number; startWidth: number } | null>(null);

    // Current time for conditional formatting
    const [now, setNow] = useState(new Date());

    useEffect(() => {
        // Update "now" every minute to refresh conditional formatting
        const timer = setInterval(() => setNow(new Date()), 60000);
        return () => clearInterval(timer);
    }, []);

    const handleStatusChange = (activityId: string, newStatus: string) => {
        onUpdateStatus(activityId, newStatus as ActivityStatus);
    };

    const handleSort = (key: keyof Activity | 'statusLabel') => {
        setSortConfig(prev => ({
            key,
            direction: prev.key === key && prev.direction === 'asc' ? 'desc' : 'asc'
        }));
    };

    const sortedActivities = useMemo(() => {
        if (!sortConfig.key) return activities;

        return [...activities].sort((a, b) => {
            let aValue: any = sortConfig.key === 'statusLabel' 
                ? getStatusLabel(a.status, customStatusLabels) 
                : a[sortConfig.key as keyof Activity];

            let bValue: any = sortConfig.key === 'statusLabel'
                ? getStatusLabel(b.status, customStatusLabels)
                : b[sortConfig.key as keyof Activity];

            // Handle undefined/null
            if (aValue === undefined || aValue === null) aValue = '';
            if (bValue === undefined || bValue === null) bValue = '';

            // Handle Date strings
            if (sortConfig.key === 'horaInicio' || sortConfig.key === 'horaFim') {
                return sortConfig.direction === 'asc' 
                    ? new Date(aValue).getTime() - new Date(bValue).getTime()
                    : new Date(bValue).getTime() - new Date(aValue).getTime();
            }

            // Handle Strings
            if (typeof aValue === 'string' && typeof bValue === 'string') {
                return sortConfig.direction === 'asc'
                    ? aValue.localeCompare(bValue)
                    : bValue.localeCompare(aValue);
            }

            return 0;
        });
    }, [activities, sortConfig, customStatusLabels]);

    // Resizing Logic
    const handleMouseDown = (e: React.MouseEvent, key: string) => {
        e.preventDefault();
        resizingRef.current = {
            key,
            startX: e.pageX,
            startWidth: columnWidths[key] || 100
        };
        document.addEventListener('mousemove', handleMouseMove);
        document.addEventListener('mouseup', handleMouseUp);
    };

    const handleMouseMove = (e: MouseEvent) => {
        if (resizingRef.current) {
            const { key, startX, startWidth } = resizingRef.current;
            const diff = e.pageX - startX;
            const newWidth = Math.max(40, startWidth + diff); 
            setColumnWidths(prev => ({ ...prev, [key]: newWidth }));
        }
    };

    const handleMouseUp = () => {
        resizingRef.current = null;
        document.removeEventListener('mousemove', handleMouseMove);
        document.removeEventListener('mouseup', handleMouseUp);
    };

    useEffect(() => {
        return () => {
            document.removeEventListener('mousemove', handleMouseMove);
            document.removeEventListener('mouseup', handleMouseUp);
        };
    }, []);

    const Th: React.FC<{ id: string; label: string; sortKey?: keyof Activity | 'statusLabel' }> = ({ id, label, sortKey }) => (
        <th 
            scope="col" 
            className="relative px-3 py-2 select-none border-r border-gray-200/50 dark:border-gray-700/50 last:border-r-0 group whitespace-nowrap"
            style={{ width: columnWidths[id] }}
        >
            <div 
                className={`flex items-center space-x-1 ${sortKey ? 'cursor-pointer hover:text-primary-600' : ''}`}
                onClick={() => sortKey && handleSort(sortKey)}
            >
                <span className="truncate">{label}</span>
                {sortKey && (
                    <span className={`transition-opacity ${sortConfig.key === sortKey ? 'opacity-100 text-primary-600' : 'opacity-30 group-hover:opacity-70'}`}>
                         <ArrowsUpDownIcon className="w-3 h-3" />
                    </span>
                )}
            </div>
            <div 
                className="absolute right-0 top-0 bottom-0 w-1 cursor-col-resize hover:bg-blue-500 z-10"
                onMouseDown={(e) => handleMouseDown(e, id)}
            ></div>
        </th>
    );

    if (activities.length === 0) {
        return <div className="text-center p-8 bg-white/70 dark:bg-gray-800/70 backdrop-blur-md rounded-lg shadow">Nenhuma atividade encontrada.</div>;
    }

    return (
        <div className="bg-white/70 dark:bg-gray-900/80 backdrop-blur-md rounded-lg shadow overflow-x-auto">
            <table className="w-full text-xs text-left text-gray-500 dark:text-gray-400 table-fixed">
                <thead className="text-xs text-gray-700 uppercase bg-gray-50/50 dark:bg-gray-700/50 dark:text-gray-300">
                    <tr>
                        <Th id="tag" label="TAG" sortKey="tag" />
                        <Th id="descricao" label="Descrição" sortKey="descricao" />
                        <Th id="responsavel" label="Responsável" sortKey="responsavel" />
                        <Th id="supervisor" label="Supervisor" sortKey="supervisor" />
                        <Th id="turno" label="Turno" sortKey="turno" />
                        <Th id="data" label="Data" sortKey="horaInicio" />
                        <Th id="horario" label="Horário" sortKey="horaInicio" />
                        <Th id="duracao" label="Duração" sortKey="duracao" />
                        <Th id="criticidade" label="Criticidade" sortKey="criticidade" />
                        <Th id="status" label="Status" sortKey="statusLabel" />
                        <Th id="anexos" label="Anexos" />
                        <Th id="acoes" label="Ações" />
                    </tr>
                </thead>
                <tbody className="divide-y divide-gray-100/50 dark:divide-gray-700/50">
                    {sortedActivities.map(activity => {
                        // Conditional Formatting Logic: Open AND Start Time < Now
                        const isOverdue = activity.status === ActivityStatus.Open && new Date(activity.horaInicio) < now;

                        return (
                            <tr key={activity.id} className="bg-transparent hover:bg-gray-50/50 dark:hover:bg-gray-700/30 transition-colors">
                                <td 
                                    className="px-3 py-1.5 font-medium text-gray-900 dark:text-white truncate overflow-hidden cursor-pointer hover:text-primary-600 hover:underline"
                                    onClick={() => onEdit(activity)}
                                    title="Clique para editar"
                                >
                                    {activity.tag}
                                </td>
                                <td 
                                    className="px-3 py-1.5 truncate overflow-hidden cursor-pointer hover:text-primary-600" 
                                    title={activity.descricao}
                                    onClick={() => onEdit(activity)}
                                >
                                    {activity.descricao}
                                </td>
                                <td className="px-3 py-1.5 truncate overflow-hidden">{activity.responsavel}</td>
                                <td className="px-3 py-1.5 truncate overflow-hidden">{activity.supervisor}</td>
                                <td className="px-3 py-1.5 truncate overflow-hidden text-center">{activity.turno}</td>
                                <td className="px-3 py-1.5 truncate overflow-hidden text-center">
                                    {new Date(activity.horaInicio).toLocaleDateString('pt-BR')}
                                </td>
                                <td className={`px-3 py-1.5 truncate overflow-hidden ${isOverdue ? 'text-red-600 font-bold dark:text-red-400' : ''}`}>
                                    {new Date(activity.horaInicio).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} - {new Date(activity.horaFim).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                </td>
                                <td className="px-3 py-1.5 truncate overflow-hidden text-center">{activity.duracao}</td>
                                <td className="px-3 py-1.5">
                                    <span className={`px-1.5 py-0.5 rounded-full text-[10px] font-semibold border ${getCriticidadeClasses(activity.criticidade)}`}>
                                        {activity.criticidade}
                                    </span>
                                </td>
                                <td className="px-3 py-1.5">
                                    <select 
                                        value={activity.status}
                                        onChange={(e) => handleStatusChange(activity.id, e.target.value)}
                                        className={`w-full p-0.5 rounded text-[10px] focus:ring-primary-500 focus:border-primary-500 cursor-pointer ${getStatusClasses(activity.status, true)}`}
                                    >
                                        {Object.values(ActivityStatus).map(s => (
                                            <option key={s} value={s} className="text-gray-800 bg-white">
                                                {getStatusLabel(s, customStatusLabels)}
                                            </option>
                                        ))}
                                    </select>
                                </td>
                                <td className="px-3 py-1.5">
                                    <div className="flex items-center justify-center space-x-1 text-gray-500 dark:text-gray-400">
                                        {(activity.beforeImage || activity.afterImage) && (
                                            <span title="Contém imagem de antes/depois">
                                                <CameraIcon className="w-4 h-4 text-blue-500" />
                                            </span>
                                        )}
                                        {(activity.attachments?.length || 0) > 0 && (
                                            <div className="flex items-center">
                                                <PaperClipIcon className="w-3.5 h-3.5" />
                                                <span className="ml-0.5 text-[10px]">{activity.attachments?.length}</span>
                                            </div>
                                        )}
                                    </div>
                                </td>
                                <td className="px-3 py-1.5 text-center">
                                    <div className="flex items-center justify-center space-x-2">
                                        <button onClick={() => onEdit(activity)} className="text-primary-600 hover:text-primary-800 dark:text-primary-500 dark:hover:text-primary-300 transition-colors" title="Editar">
                                            <PencilIcon className="w-4 h-4"/>
                                        </button>
                                        {onDelete && (
                                            <button onClick={() => onDelete(activity.id)} className="text-red-500 hover:text-red-700 transition-colors" title="Excluir">
                                                <TrashIcon className="w-4 h-4" />
                                            </button>
                                        )}
                                    </div>
                                </td>
                            </tr>
                        );
                    })}
                </tbody>
            </table>
        </div>
    );
};

import React, { useState } from 'react';
import type { Activity } from '../types';
import { getStatusClasses, getStatusLabel } from '../utils/styleUtils';

interface ActivityCalendarViewProps {
    activities: Activity[];
    onEdit: (activity: Activity) => void;
    customStatusLabels?: Record<string, string>;
    onDateChange: (activityId: string, newDate: Date) => void;
}

export const ActivityCalendarView: React.FC<ActivityCalendarViewProps> = ({ activities, onEdit, customStatusLabels = {}, onDateChange }) => {
    const [currentDate, setCurrentDate] = useState(new Date());

    const getDaysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate();
    const getFirstDayOfMonth = (year: number, month: number) => new Date(year, month, 1).getDay();

    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();

    const daysInMonth = getDaysInMonth(year, month);
    const firstDay = getFirstDayOfMonth(year, month);

    const prevMonth = () => setCurrentDate(new Date(year, month - 1, 1));
    const nextMonth = () => setCurrentDate(new Date(year, month + 1, 1));
    const goToToday = () => setCurrentDate(new Date());

    const monthNames = [
        "Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho",
        "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"
    ];

    const dayNames = ["Dom", "Seg", "Ter", "Qua", "Qui", "Sex", "Sáb"];

    // Group activities by day
    const activitiesByDay: Record<number, Activity[]> = {};
    activities.forEach(activity => {
        const actDate = new Date(activity.horaInicio);
        if (actDate.getFullYear() === year && actDate.getMonth() === month) {
            const day = actDate.getDate();
            if (!activitiesByDay[day]) activitiesByDay[day] = [];
            activitiesByDay[day].push(activity);
        }
    });

    const handleDragStart = (e: React.DragEvent, id: string) => {
        e.dataTransfer.setData("text/plain", id);
        e.dataTransfer.effectAllowed = "move";
    };

    const handleDragOver = (e: React.DragEvent) => {
        e.preventDefault(); // Necessary to allow dropping
    };

    const handleDrop = (e: React.DragEvent, day: number) => {
        e.preventDefault();
        const id = e.dataTransfer.getData("text/plain");
        if (id) {
            const targetDate = new Date(year, month, day);
            onDateChange(id, targetDate);
        }
    };

    // Grid generation
    const days = [];
    // Empty cells for days before the first of the month
    for (let i = 0; i < firstDay; i++) {
        days.push(<div key={`empty-${i}`} className="bg-gray-50/50 dark:bg-gray-900/30 min-h-[100px] border-r border-b border-gray-200/50 dark:border-gray-700/50"></div>);
    }

    // Actual days
    for (let day = 1; day <= daysInMonth; day++) {
        const isToday = 
            new Date().getDate() === day && 
            new Date().getMonth() === month && 
            new Date().getFullYear() === year;

        const dayActivities = activitiesByDay[day] || [];

        days.push(
            <div 
                key={day} 
                className={`min-h-[120px] border-r border-b border-gray-200/50 dark:border-gray-700/50 p-2 transition-colors hover:bg-gray-50/50 dark:hover:bg-gray-700/30 ${isToday ? 'bg-blue-50/80 dark:bg-blue-900/40' : 'bg-white/60 dark:bg-gray-800/60'}`}
                onDragOver={handleDragOver}
                onDrop={(e) => handleDrop(e, day)}
            >
                <div className="flex justify-between items-center mb-2">
                    <span className={`text-sm font-bold w-7 h-7 flex items-center justify-center rounded-full ${isToday ? 'bg-blue-600 text-white' : 'text-gray-700 dark:text-gray-300'}`}>
                        {day}
                    </span>
                    {dayActivities.length > 0 && (
                        <span className="text-xs text-gray-500 font-mono">{dayActivities.length} atv</span>
                    )}
                </div>

                <div className="space-y-1 overflow-y-auto max-h-[100px] scrollbar-thin scrollbar-thumb-gray-300 dark:scrollbar-thumb-gray-600">
                    {dayActivities.map(act => (
                        <div 
                            key={act.id}
                            draggable
                            onDragStart={(e) => handleDragStart(e, act.id)}
                            onClick={(e) => { e.stopPropagation(); onEdit(act); }}
                            className={`text-[10px] px-1.5 py-1 rounded cursor-grab active:cursor-grabbing truncate border-l-2 shadow-sm hover:opacity-80 ${getStatusClasses(act.status, false).replace('text-xs', '').replace('font-bold', 'font-medium').replace('uppercase', '')}`}
                            title={`${act.tag} - ${act.descricao}`}
                        >
                            <span className="font-bold mr-1">{new Date(act.horaInicio).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                            <span className="font-semibold mr-1">{act.tag}</span>
                            <span className="opacity-90">- {act.descricao}</span>
                        </div>
                    ))}
                </div>
            </div>
        );
    }

    return (
        <div className="bg-white/70 dark:bg-gray-900/80 backdrop-blur-md rounded-lg shadow-lg overflow-hidden border border-gray-200/50 dark:border-gray-700/50">
            {/* Calendar Header */}
            <div className="flex items-center justify-between p-4 border-b border-gray-200/50 dark:border-gray-700/50 bg-gray-50/50 dark:bg-gray-800/50">
                <div className="flex items-center space-x-4">
                    <h2 className="text-xl font-bold text-gray-800 dark:text-white capitalize">
                        {monthNames[month]} {year}
                    </h2>
                    <div className="flex items-center space-x-1">
                        <button onClick={prevMonth} className="p-1 rounded hover:bg-gray-200/50 dark:hover:bg-gray-700/50 text-gray-600 dark:text-gray-300">
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
                        </button>
                        <button onClick={goToToday} className="px-3 py-1 text-xs font-medium bg-blue-100 text-blue-700 dark:bg-blue-900 dark:text-blue-300 rounded hover:bg-blue-200 dark:hover:bg-blue-800">
                            Hoje
                        </button>
                        <button onClick={nextMonth} className="p-1 rounded hover:bg-gray-200/50 dark:hover:bg-gray-700/50 text-gray-600 dark:text-gray-300">
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>
                        </button>
                    </div>
                </div>
                <div className="text-sm text-gray-500 dark:text-gray-400">
                    {activities.length} Atividades Totais
                </div>
            </div>

            {/* Weekdays Header */}
            <div className="grid grid-cols-7 border-b border-gray-200/50 dark:border-gray-700/50 bg-gray-100/50 dark:bg-gray-900/50">
                {dayNames.map(day => (
                    <div key={day} className="py-2 text-center text-sm font-semibold text-gray-600 dark:text-gray-400">
                        {day}
                    </div>
                ))}
            </div>

            {/* Calendar Grid */}
            <div className="grid grid-cols-7 bg-gray-200/50 dark:bg-gray-700/50 gap-px border-l border-gray-200/50 dark:border-gray-700/50">
                {days}
            </div>
        </div>
    );
};
